end

function LCityUnitView:InnerInitFsm()
    self._unitFsm = require("LApp.gameplay.city.fsm.LCityUnitFsm"):new()
    self._unitFsm:SetVar("OwnerView", self)
    self._unitFsm:Initialize()
    self._unitFsm:SetUpdateFrequency(0.1)
end

function LCityUnitView:InnerInitData(unitData)
    self._unitData = unitData

    self._directSpeed = unitData.speed
end

function LCityUnitView:GetId()
    return self._unitData.id
end

function LCityUnitView:FitMovePos(pos)
    if not pos or not pos.x or not pos.y then
        return nil
    end
    local movePos = Vector3.zero
    movePos.x = pos.x
    movePos.z = pos.y / math.tan(math.angle2radian(20))
    movePos.y = 0
    return movePos
end

