---@param spineDp LxSpineDp
function LCityUnitView:OnLoadModel(spineDp)
    if self._cRenderer2D then
        self._cRenderer2D:InitRenderers()
        self._cRenderer2D:UpdateRenderersLayer()
    end
    self._modelAniMap = {}
    local aniList = spineDp:GetAniNameStrList()
    for i, v in ipairs(aniList) do
        self._modelAniMap[v] = true
    end
    self:PlayIdle()
    if self._loadCallback then
        self._loadCallback(self)
    end
end

function LCityUnitView:PlayIdle()
    --if not self._modelDp then
    --    return
    --end
    --if self._modelAniMap['idle1'] then
    --    self._modelDp:PlayAni('idle1')
    --else
    --    self._modelDp:PlayAni('idle')
    --end
    if not self._spineDp then return end
    local aniName = "idle1"
    if not self._modelAniMap[aniName] then
        aniName = "idle"
    end
    self._spineDp:PlayAni(aniName,true,false)
end

function LCityUnitView:InitComponent()
    local modelRoot = self._modelRoot

    local cRole = modelRoot:GetComponent(typeOfRoleObject)
    if cRole == nil then
        cRole = modelRoot:AddComponent(typeOfRoleObject)
    end
    self._cRoleObj = cRole
    cRole.isPause = false
    cRole.isMoving = false
    cRole.isDirectMove = false
    cRole.OnMoveEnd = function()
        self:OnMoveEnd()
    end


    local cRenderer2D = modelRoot:GetComponent(typeOfRenderer2d)
    if not cRenderer2D then
        cRenderer2D = modelRoot:AddComponent(typeOfRenderer2d)
    end
    self._cRenderer2D = cRenderer2D
    self._cRenderer2D.sortingLayerName = LayerMaskNames.Object

end

---@param callback fun(obj:LCityUnitView)
function LCityUnitView:SetLoadCallback(callback)
    self._loadCallback = callback
end

function LCityUnitView:OnUpdate(deltaTime)
    if self._isDisposed then
        return
    end

    if self._unitFsm then
        self._unitFsm:OnUpdate(deltaTime)
    end
end

function LCityUnitView:SetPosition(pos)
    self._curPos = pos
    self:SetTransPosition(self:FitMovePos(pos))
end

function LCityUnitView:GetPosition()
    local pos = self:GetTransPosition()
    local rPos = Vector3(0, 0, 0)
    rPos.x = pos.x
    rPos.y = pos.z * math.tan(math.angle2radian(20))
    rPos.z = 0
    return rPos
end

function LCityUnitView:SetTransPosition(pos)
    if not pos or tonumber(pos.x) == nil then
        return
    end
    self._modelRootTrans.localPosition = pos
end

function LCityUnitView:GetTransPosition()
    return self._modelRootTrans.localPosition
end

function LCityUnitView:GetDirectSpeed()
    return self._directSpeed
end

function LCityUnitView:Move(pos)
    pos.z = 0
    local speed = self._directSpeed
    local dis = Vector2.Distance(self:GetPosition(), pos)
    local time = dis / speed
    self:DoMoveTo(pos, time)
end

function LCityUnitView:DoMoveTo(pos, time)
    if not self._cRoleObj then return end
    local oldPos = self._spineDp:GetDpTrans().position
    local obj = self._cRoleObj
    obj.moveType = 0
    if not obj.isMoving then
        obj.isDirectMove = false
        obj.isIgnoreZ = false
        obj.isMoving = true
        --self._modelDp:PlayAni("run")
        self._spineDp:PlayAni("run",true,false)
    end
    self._moveToPos = pos
    pos = self:FitMovePos(pos)
    if not pos then
        return
    end
    obj:MoveTo(pos, time, 0)

    self:UpdateFlipX(oldPos,pos)
    --self:Forward(pos - self._modelRootTrans.localPosition)
end

function LCityUnitView:Forward(dirPos)
    if not dirPos then
        return
    end
    local dir = Vector3.Normalize(dirPos)
    if dir.magnitude > 0 then
        --self._modelDp:SetForward(dir)
        self._spineDp:SetForward(dir)
    end
end

function LCityUnitView:UpdateFlipX(oldPos,newPos)
    if not self._spineDp then return end
    local bFilp = oldPos.x - newPos.x > 0
    self._spineDp:SetFlipX(bFilp)
end

function LCityUnitView:SetMoveEndFun(func)
    self._moveEndFun = func
end

function LCityUnitView:OnMoveEnd()
    if self._moveToPos then
        self:SetPosition(self._moveToPos)
        self._moveToPos = nil
    end
    if self._moveEndFun then
        self._moveEndFun()
        return
    end
    self:PlayIdle()
end

function LCityUnitView:DirectMove(directPos, direct)
    if not self._isDirectMoving then
        self._cRoleObj.isDirectMove = false
        self._cRoleObj.isMoving = false
        self._isDirectMoving = true
        --self._modelDp:PlayAni("run")
        self._spineDp:PlayAni("run",true,false)
    end
    local curPos = self:FitMovePos(self._curPos)
    local movePos = self:FitMovePos(directPos)

    self._curPos = directPos

    self:UpdateFlipX(curPos,movePos)
    --self:Forward(self:FitMovePos(direct))
    self:SetTransPosition(movePos)
end

function LCityUnitView:PathMove(pathList, callback)
    self._unitFsm:SetVar("pathDataList", pathList)
    self._unitFsm:ChangeState(CityFsmState.Path)
    self._pathCallback = callback
end

function LCityUnitView:OnPathMoveEnd()
    local callback = self._pathCallback
    self._callback = nil
    if callback ~= nil then
        callback()
    end
end

function LCityUnitView:StopMove()
    if not self._cRoleObj then return end
    local obj = self._cRoleObj
    obj.isMoving = false
    obj.isDirectMove = false
    self._isDirectMoving = false
    self:PlayIdle()
end

function LCityUnitView:GetModelRootTrans()
    return self._modelRootTrans
end

function LCityUnitView:GetType()
    return self._unitData.type
end

return LCityUnitView